from pandera.typing import DataFrame

class RawOrderSchema(pa.SchemaModel):
    order_id: Series[int]
    unit_price: Series[float]
    quantity: Series[int]

class EnrichedOrderSchema(RawOrderSchema):
    total_price: Series[float]  # derived column

@pa.check_types
def compute_totals(df: DataFrame[RawOrderSchema]) -> DataFrame[EnrichedOrderSchema]:
    df = df.copy()
    df["total_price"] = df["unit_price"] * df["quantity"]
    return df

# Element-wise check (called once per cell)
def is_valid_sku(sku: str) -> bool:
    return sku.startswith("SKU-") and len(sku) == 8

# Vectorized check (called once per column, must return bool Series)
def no_future_dates(dates: pd.Series) -> pd.Series:
    return dates <= pd.Timestamp.now()

class OrderSchema(pa.SchemaModel):
    product_sku: Series[str] = pa.Field()
    order_date: Series[pd.Timestamp] = pa.Field()

    @pa.check("product_sku", element_wise=True)
    def check_sku_format(cls, sku: str) -> bool:
        return is_valid_sku(sku)

    @pa.check("order_date", element_wise=False)
    def check_no_future_orders(cls, dates: pd.Series) -> pd.Series:
        return no_future_dates(dates)

class OrderSchema(pa.SchemaModel):
    discount: Series[float] = pa.Field(ge=0.0, le=1.0)
    unit_price: Series[float] = pa.Field(ge=0.0)

    @pa.dataframe_check
    def discount_not_applied_to_zero_price(cls, df: pd.DataFrame) -> pd.Series:
        # If price is 0, discount must also be 0
        return ~((df["unit_price"] == 0) & (df["discount"] > 0))

class RawUserSchema(pa.SchemaModel):
    user_id: Series[int] = pa.Field(gt=0, unique=True)
    raw_email: Series[str]

class CleanUserSchema(RawUserSchema):
    email: Series[str] = pa.Field(str_contains="@")  # normalized
    domain: Series[str]  # extracted from email

@pa.check_types
def normalize_users(df: DataFrame[RawUserSchema]) -> DataFrame[CleanUserSchema]:
    df = df.copy()
    df["email"] = df["raw_email"].str.strip().str.lower()
    df["domain"] = df["email"].str.split("@").str[1]
    return df

