class ChurnFeatureSchema(pa.SchemaModel):
    user_id: Series[int] = pa.Field(gt=0, unique=True)
    days_since_last_purchase: Series[int] = pa.Field(ge=0, le=3650)
    total_purchase_count_90d: Series[int] = pa.Field(ge=0)
    avg_session_length_minutes: Series[float] = pa.Field(ge=0.0)
    cart_abandonment_rate: Series[float] = pa.Field(ge=0.0, le=1.0)

