    def no_all_zero_features(cls, df: pd.DataFrame) -> pd.Series:
        # A user with all-zero features is likely a pipeline error, not a real user
        numeric_cols = df.select_dtypes(include="number").drop(columns="user_id")
        return numeric_cols.sum(axis=1) > 0

